import { Component, OnInit } from '@angular/core';
import { Certification } from '../../shared/models';
import { PortfolioService } from '../../core/services/portfolio.service';

@Component({
  selector: 'app-certifications',
  templateUrl: './certifications.component.html',
  styleUrls: ['./certifications.component.scss']
})
export class CertificationsComponent implements OnInit {
  certifications: Certification[] = [];

  constructor(private portfolioService: PortfolioService) {}

  ngOnInit(): void {
    this.portfolioService.getCertifications().subscribe(c => this.certifications = c);
  }
}
<section class="section">
  <div class="container">
    <span class="term-label">ls -la certifications/</span>
    <h1>Certifications</h1>

    <div class="grid grid--2">
      <div class="card cert" *ngFor="let c of certifications">
        <h3>{{ c.title }}</h3>
        <p class="cert__issuer">{{ c.issuer }}</p>
        <span class="tag" *ngIf="c.inProgress">In Progress</span>
      </div>
    </div>
  </div>
</section>
